import scala.collection.mutable.{Queue, ArrayBuffer, HashMap}

def solve(nums: Array[Long]): Long = {
    val n = nums.length
    if (n == 1) return 0L

    // Precompute primes up to 1e6 using Sieve of Eratosthenes
    val maxNum = nums.max.max(1000000L) // Handle cases where nums has larger numbers
    val isPrime = Array.fill(maxNum.toInt + 1)(true)
    isPrime(0) = false
    isPrime(1) = false
    for (i <- 2 to math.sqrt(maxNum).toInt) {
        if (isPrime(i)) {
            for (j <- i * i to maxNum.toInt by i) {
                isPrime(j) = false
            }
        }
    }

    // Build a map from primes to indices where nums[j] is divisible by the prime
    val primeToIndices = HashMap[Long, ArrayBuffer[Int]]()
    for (i <- nums.indices) {
        val num = nums(i)
        if (num > 1 && isPrime(num.toInt)) {
            val p = num
            if (!primeToIndices.contains(p)) {
                primeToIndices(p) = ArrayBuffer[Int]()
            }
            primeToIndices(p) += i
        }
    }

    // For each number, precompute all primes that divide it (for quick lookup during BFS)
    val numToPrimes = Array.tabulate(n)(i => {
        val num = nums(i)
        val primes = ArrayBuffer[Long]()
        if (num > 1) {
            if (isPrime(num.toInt)) {
                primes += num
            } else {
                var temp = num
                var p = 2L
                while (p * p <= temp) {
                    if (temp % p == 0) {
                        if (isPrime(p.toInt)) {
                            primes += p
                        }
                        while (temp % p == 0) {
                            temp /= p
                        }
                    }
                    p += 1
                }
                if (temp > 1 && isPrime(temp.toInt)) {
                    primes += temp
                }
            }
        }
        primes.toArray
    })

    val visited = Array.fill(n)(false)
    val queue = Queue[(Int, Long)]()
    queue.enqueue((0, 0L))
    visited(0) = true

    while (queue.nonEmpty) {
        val (current, steps) = queue.dequeue()
        if (current == n - 1) {
            return steps
        }

        // Move to adjacent indices
        val neighbors = ArrayBuffer[Int]()
        if (current > 0) neighbors += current - 1
        if (current < n - 1) neighbors += current + 1

        for (neighbor <- neighbors) {
            if (!visited(neighbor)) {
                visited(neighbor) = true
                queue.enqueue((neighbor, steps + 1))
            }
        }

        // Check if current number is prime, then teleport
        val num = nums(current)
        if (num > 1 && isPrime(num.toInt)) {
            val p = num
            if (primeToIndices.contains(p)) {
                for (j <- primeToIndices(p)) {
                    if (j != current && !visited(j)) {
                        visited(j) = true
                        queue.enqueue((j, steps + 1))
                    }
                }
            }
        }

        // Check if current number is divisible by any prime, then teleport to all indices with that prime
        for (p <- numToPrimes(current)) {
            if (primeToIndices.contains(p)) {
                for (j <- primeToIndices(p)) {
                    if (j != current && !visited(j)) {
                        visited(j) = true
                        queue.enqueue((j, steps + 1))
                    }
                }
            }
        }
    }

    -1L // Shouldn't reach here for valid inputs
}
